{
      "@context": "https://schema.org",
      "@type": "FAQPage",
      "mainEntity": [{
        "@type": "Question",
        "name": "I have some specific seats I want to purchase but I cannot select them, why can't I buy these seats?",
        "acceptedAnswer": {
          "@type": "Answer",
          "text": "Our systems automatically select the best available seat for a selected area. If you need a specific seat please contact the Ticket Enquiry Line on 0871 226 1888 option 1 then option 2 and one of the operators will be able to assist you. For customer enquiries relating to existing purchases only, please call 0141 230 1967.Calls charged at standard rate, calls cost 13p per minute, plus your phone company’s access charge, booking fees apply online and via booking line."
          }
     }, {
        "@type": "Question",
        "name": "I have been asked for a CV2 number. What is this?",
        "acceptedAnswer": {
          "@type": "Answer",
          "text": "This is the last 3 digits of the number on the signature strip on a credit or debit card (usually on the right side of the signature strip)."
         }
      }, {
        "@type": "Question",
        "name": "I have purchased tickets online but have not received a confirmation e-mail. Does this mean my purchase has not gone through?",
        "acceptedAnswer": {
          "@type": "Answer",
          "text": "Possibly, please check your e-mail address is correctly registered with us. If this is registered incorrectly no confirmation e-mail will have been sent. If your e-mail address is correctly registered with us please contact 0871 226 1888 option 1 then option 2 and we will check your booking. Calls cost 13p per minute, plus your phone company’s access charge. Booking fees apply online and via booking line. For customer enquiries relating to existing purchases only, please call 0141 230 1967. Calls charged at standard rate."
         }
      }, {
        "@type": "Question",
        "name": "What happens if I cannot make the game after I have purchased the ticket?",
        "acceptedAnswer": {
          "@type": "Answer",
          "text": "There is no refund policy on returned match tickets."
         }
      }, {
        "@type": "Question",
        "name": "How do I use my ticket at the turnstiles?",
        "acceptedAnswer": {
          "@type": "Answer",
          "text": "When you walk into the turnstile, please insert the barcode end of the ticket face up into the reader and wait for a green light. Once the green light appears, please walk through the turnstile. Please note there is a time limit on this process."
         }
      }, {
        "@type": "Question",
        "name": "What happens if the turnstile does not open or if there is no light?",
        "acceptedAnswer": {
          "@type": "Answer",
          "text": "This could be because the ticket was not properly inserted or the ticket did not read. Try again and if it is still not working please make your way to the Ticket Office where the staff will check the ticket for you."
         }
      }, {
        "@type": "Question",
        "name": "Can I book tickets and pick them up from the shop?",
        "acceptedAnswer": {
          "@type": "Answer",
          "text": "No, tickets purchased online will automatically be posted out as per the details on your confirmation email. If you want to arrange to have your tickets collected you have to contact the Ticket Enquiry line on 0871 226 1888 option 1 then option 2 to arrange. Calls cost 13p per minute, plus your phone company’s access charge. Booking fees apply online and via booking line. For customer enquiries relating to existing purchases only, please call 0141 230 1967. Calls charged at standard rate."
         }
      }, {
        "@type": "Question",
        "name": "What is a restricted view seat?",
        "acceptedAnswer": {
          "@type": "Answer",
          "text": "Restricted view seats are seats where there is a restriction to the view of the goal mouth area on either side of the pitch. On certain seats, there is a discount on the match price when purchasing these seats. Tickets for these seats will always have restricted view printed on them."
         }
      }, {
        "@type": "Question",
        "name": "What happens if the game has to be re-scheduled?",
        "acceptedAnswer": {
          "@type": "Answer",
          "text": "In most cases the ticket purchased for the original seat will be valid for any re-scheduled match. If you are unsure, please contact the ticket enquiry line on 0871 226 1888 option 1 then option 2. Calls cost 13p per minute, plus your phone company’s access charge. Booking fees apply online and via booking line. For customer enquiries relating to existing purchases only, please call 0141 230 1967. Calls charged at standard rate."
         }
      }, {
        "@type": "Question",
        "name": "How can I get tickets for a disabled supporter?",
        "acceptedAnswer": {
          "@type": "Answer",
          "text": "If you contact our Ticket Office on 0871 226 1888 one of our staff will be able to assist you. Calls cost 13p per minute, plus your phone company’s access charge. Booking fees apply online and via booking line. For customer enquiries relating to existing purchases only, please call 0141 230 1967. Calls charged at standard rate."
         }
      }, {
        "@type": "Question",
        "name": "What happens if my ticket is presented and a red light shows?",
        "acceptedAnswer": {
          "@type": "Answer",
          "text": "If this happens, you will need to visit the Ticket Office."
         }
      }, {
        "@type": "Question",
        "name": "Can I remove the stub from the ticket and insert this into the turnstile reader?",
        "acceptedAnswer": {
          "@type": "Answer",
          "text": "No, this will render your ticket invalid. You will need to leave the stub on the ticket. If the stub has been removed please go straight to the Ticket Office to have your ticket checked."
         }
      }, {
        "@type": "Question",
        "name": "My ticket is damaged what can I do?",
        "acceptedAnswer": {
          "@type": "Answer",
          "text": "You need to bring the damaged ticket to the Ticket Office where the ticket will be checked."
         }
      }, {
        "@type": "Question",
        "name": "Where can I find a stadium plan?",
        "acceptedAnswer": {
          "@type": "Answer",
          "text": "The layout of the stadium and car park details can be found at https://www.celticfc.com/visit-celtic-park/getting-to-celtic-park/celtic-park-maps/."
        }
      }, {
        "@type": "Question",
        "name": "I have purchased tickets and they have not arrived by post?",
        "acceptedAnswer": {
          "@type": "Answer",
          "text": "Matchday Saturday/Sunday - All tickets booked after Wednesday afternoon prior to the match will be made available for collection from the ticket office. Matchday Tuesday/Wednesday - All tickets booked after the Thursday prior to the match will be made available for collection from the ticket office. Matchday Thursday - All tickets booked after the Monday prior to the match will be made available for collection from the ticket office. All bookings with a delivery address out with the UK (excluding the Republic of Ireland) will automatically be retained in the ticket office for collection. If you have not received your ticket the day prior to the match, please contact the enquiry line on 0871 226 1888 option 1 then option 2. Please have your booking information ready as you will be asked to confirm various details. Calls cost 13p per minute, plus your phone company’s access charge. Booking fees apply online and via booking line. For customer enquiries relating to existing purchases only, please call 0141 230 1967. Calls charged at standard rate."
        }
      }, {
        "@type": "Question",
        "name": "I have forgotten my match tickets, what happens?",
        "acceptedAnswer": {
          "@type": "Answer",
          "text": "If you have forgotten to bring your ticket to the match, please visit the Ticket Office. You will need to bring your booking confirmation and identification as you will be asked to confirm details. An administration fee is applicable for a reprint."
        }
      }, {
        "@type": "Question",
        "name": "I have lost my match tickets, what do I do?",
        "acceptedAnswer": {
          "@type": "Answer",
          "text": "If you have lost your ticket prior to the match, please contact the enquiry line on 0871 226 1888 option 1 then option 2. An administration fee is applicable for a reprint. Calls cost 13p per minute, plus your phone company’s access charge. Booking fees apply online and via booking line. For customer enquiries relating to existing purchases only, please call 0141 230 1967. Calls charged at standard rate."
           }
        }]
    }

